// Hands-on YAML / kubectl examples (deep dive).
const examples = {
  'k8s-kubectl': { title: l('The everyday kubectl loop', 'প্রতিদিনের kubectl লুপ'), lang: 'bash', code: 'kubectl apply -f app.yaml     # create or update from a manifest\nkubectl get pods              # see what is running\nkubectl describe pod web-xyz  # events and current state\nkubectl logs -f web-xyz       # follow the container output', note: l('apply is declarative — run it again after editing the file and Kubernetes reconciles the difference.', 'apply ডিক্লারেটিভ — ফাইল এডিটের পর আবার চালান, কুবারনেটিস পার্থক্য মেলায়।') },
  'k8s-pods': { title: l('A minimal Pod manifest', 'একটি ন্যূনতম Pod ম্যানিফেস্ট'), lang: 'yaml', code: 'apiVersion: v1\nkind: Pod\nmetadata:\n  name: web\n  labels:\n    app: web\nspec:\n  containers:\n    - name: nginx\n      image: nginx:1.25\n      ports:\n        - containerPort: 80', note: l('In practice you rarely create bare Pods — a Deployment manages them for you.', 'বাস্তবে খালি Pod কমই বানান — একটি Deployment আপনার জন্য এদের সামলায়।') },
  'k8s-multicontainer': { title: l('App container plus a logging sidecar', 'অ্যাপ কন্টেইনার ও একটি লগিং সাইডকার'), lang: 'yaml', code: 'spec:\n  containers:\n    - name: app\n      image: myorg/app:1.0\n    - name: log-shipper\n      image: fluent/fluent-bit\n      # both share the pod network and can mount the same volume', note: l('The two containers share localhost and volumes, so the sidecar can read the app’s logs.', 'দুই কন্টেইনার localhost ও ভলিউম শেয়ার করে, তাই সাইডকার অ্যাপের লগ পড়তে পারে।') },
  'k8s-namespaces': { title: l('Create and use a namespace', 'একটি নেমস্পেস তৈরি ও ব্যবহার'), lang: 'bash', code: 'kubectl create namespace dev\nkubectl apply -f app.yaml -n dev\nkubectl get pods -n dev\n\n# make dev the default for this context\nkubectl config set-context --current --namespace=dev', note: l('Setting the default namespace saves typing -n on every command in this environment.', 'ডিফল্ট নেমস্পেস সেট করলে এই এনভায়রনমেন্টে প্রতিটি কমান্ডে -n টাইপ করা বাঁচে।') },
  'k8s-deployment': { title: l('A Deployment with three replicas', 'তিন রেপ্লিকার একটি Deployment'), lang: 'yaml', code: 'apiVersion: apps/v1\nkind: Deployment\nmetadata:\n  name: web\nspec:\n  replicas: 3\n  selector:\n    matchLabels:\n      app: web\n  template:\n    metadata:\n      labels:\n        app: web\n    spec:\n      containers:\n        - name: web\n          image: nginx:1.25', note: l('The selector must match the pod template labels, or the Deployment manages zero pods.', 'সিলেক্টর পড টেমপ্লেট লেবেলের সঙ্গে মিলতে হবে, না হলে Deployment শূন্য পড সামলায়।') },
  'k8s-rollout': { title: l('Update and roll back a Deployment', 'একটি Deployment আপডেট ও রোলব্যাক'), lang: 'bash', code: 'kubectl set image deploy/web web=nginx:1.26\nkubectl rollout status deploy/web    # watch the rollout\n\n# something broke? revert instantly\nkubectl rollout undo deploy/web', note: l('Kubernetes replaces pods gradually and keeps the previous ReplicaSet so undo is instant.', 'কুবারনেটিস ধীরে পড বদলায় ও আগের ReplicaSet রাখে, তাই undo তাৎক্ষণিক।') },
  'k8s-jobs': { title: l('A CronJob that runs every night', 'প্রতি রাতে চলা একটি CronJob'), lang: 'yaml', code: 'apiVersion: batch/v1\nkind: CronJob\nmetadata:\n  name: nightly-backup\nspec:\n  schedule: "0 2 * * *"\n  jobTemplate:\n    spec:\n      template:\n        spec:\n          restartPolicy: OnFailure\n          containers:\n            - name: backup\n              image: myorg/backup:1.0', note: l('The schedule uses standard cron syntax — here, 02:00 every day.', 'শিডিউল প্রমিত cron সিনট্যাক্স ব্যবহার করে — এখানে প্রতিদিন ০২:০০।') },
  'k8s-service': { title: l('A ClusterIP Service for the web pods', 'web পডের জন্য একটি ClusterIP Service'), lang: 'yaml', code: 'apiVersion: v1\nkind: Service\nmetadata:\n  name: web\nspec:\n  selector:\n    app: web\n  ports:\n    - port: 80\n      targetPort: 80', note: l('The selector app: web makes this Service load-balance across every pod with that label.', 'সিলেক্টর app: web এই Service-কে সেই লেবেলের প্রতিটি পডে লোড-ব্যালান্স করায়।') },
  'k8s-ingress': { title: l('An Ingress routing by path', 'পাথ অনুযায়ী রাউট করা একটি Ingress'), lang: 'yaml', code: 'apiVersion: networking.k8s.io/v1\nkind: Ingress\nmetadata:\n  name: site\nspec:\n  rules:\n    - host: example.com\n      http:\n        paths:\n          - path: /api\n            pathType: Prefix\n            backend:\n              service:\n                name: api\n                port:\n                  number: 80', note: l('You also need an ingress controller (like nginx-ingress) running for these rules to take effect.', 'এই নিয়ম কার্যকর হতে একটি ingress কন্ট্রোলার (যেমন nginx-ingress) চলাও দরকার।') },
  'k8s-configmap': { title: l('A ConfigMap injected as env vars', 'env ভ্যার হিসেবে দেওয়া একটি ConfigMap'), lang: 'yaml', code: 'apiVersion: v1\nkind: ConfigMap\nmetadata:\n  name: app-config\ndata:\n  LOG_LEVEL: info\n  FEATURE_X: "true"\n---\n# in the pod spec:\nenvFrom:\n  - configMapRef:\n      name: app-config', note: l('envFrom turns every key in the ConfigMap into an environment variable in the container.', 'envFrom ConfigMap-এর প্রতিটি কী-কে কন্টেইনারে একটি এনভায়রনমেন্ট ভ্যারিয়েবল করে।') },
  'k8s-secret': { title: l('A Secret referenced as an env var', 'env ভ্যার হিসেবে রেফার করা একটি Secret'), lang: 'yaml', code: 'env:\n  - name: DB_PASSWORD\n    valueFrom:\n      secretKeyRef:\n        name: db\n        key: pw', note: l('The pod reads the value at runtime; the raw secret never has to appear in the pod manifest.', 'পড রানটাইমে মান পড়ে; কাঁচা সিক্রেট পড ম্যানিফেস্টে কখনো দেখাতে হয় না।') },
  'k8s-resources': { title: l('Requests and limits on a container', 'একটি কন্টেইনারে request ও limit'), lang: 'yaml', code: 'resources:\n  requests:\n    cpu: "250m"\n    memory: "256Mi"\n  limits:\n    cpu: "500m"\n    memory: "512Mi"', note: l('requests guide scheduling; limits cap usage. 250m means a quarter of one CPU core.', 'requests শিডিউলিং নির্দেশ করে; limits ব্যবহার সীমিত করে। 250m মানে এক CPU কোরের এক-চতুর্থাংশ।') },
  'k8s-probes': { title: l('Liveness and readiness probes', 'liveness ও readiness প্রোব'), lang: 'yaml', code: 'readinessProbe:\n  httpGet:\n    path: /ready\n    port: 8080\n  initialDelaySeconds: 5\nlivenessProbe:\n  httpGet:\n    path: /health\n    port: 8080\n  periodSeconds: 10', note: l('Readiness gates traffic until the app is up; liveness restarts it if it later hangs.', 'readiness অ্যাপ চালু না হওয়া পর্যন্ত ট্রাফিক আটকায়; liveness পরে ঝুলে গেলে রিস্টার্ট করে।') },
  'k8s-pv-pvc': { title: l('A PersistentVolumeClaim', 'একটি PersistentVolumeClaim'), lang: 'yaml', code: 'apiVersion: v1\nkind: PersistentVolumeClaim\nmetadata:\n  name: data\nspec:\n  accessModes:\n    - ReadWriteOnce\n  resources:\n    requests:\n      storage: 10Gi', note: l('A pod mounts this claim; the PVC binds to a matching PV so the data outlives the pod.', 'একটি পড এই ক্লেইম মাউন্ট করে; PVC একটি মেলা PV-তে বাঁধে যাতে ডেটা পডের চেয়ে বেশি টেকে।') },
  'k8s-hpa': { title: l('A Horizontal Pod Autoscaler', 'একটি হরাইজন্টাল পড অটোস্কেলার'), lang: 'yaml', code: 'apiVersion: autoscaling/v2\nkind: HorizontalPodAutoscaler\nmetadata:\n  name: web\nspec:\n  scaleTargetRef:\n    apiVersion: apps/v1\n    kind: Deployment\n    name: web\n  minReplicas: 2\n  maxReplicas: 10\n  metrics:\n    - type: Resource\n      resource:\n        name: cpu\n        target:\n          type: Utilization\n          averageUtilization: 70', note: l('The HPA keeps average CPU near 70%, adding pods under load and removing them when idle. It needs CPU requests set.', 'HPA গড় CPU ৭০%-এর কাছে রাখে, লোডে পড যোগ ও অলস হলে সরায়। এতে CPU request সেট থাকা লাগে।') },
}

