export const k8sTopics = rawTopics.map((row, index) => {
  const [id, moduleId, en, bn, difficulty, minutes, diagram, insightEn, insightBn, analogyEn, analogyBn, actionEn, actionBn, tradeoffEn, tradeoffBn, mistakeEn, mistakeBn] = row
  const topic = {
    id, order: index + 1, moduleId, title: l(en, bn), difficulty, minutes, diagram, deepDive: null,
    insight: l(insightEn, insightBn), analogy: l(analogyEn, analogyBn), action: l(actionEn, actionBn), tradeoff: l(tradeoffEn, tradeoffBn), mistake: l(mistakeEn, mistakeBn),
    complexity: (commands[id] || []).map(([opEn, opBn, value]) => ({ op: l(opEn, opBn), value })),
    example: examples[id] || null,
    guide: k8sGuides[id] || null,
    objectives: [
      l(`Explain ${en} in plain language.`, `সহজ ভাষায় ${bn} ব্যাখ্যা করতে পারবেন।`),
      l('Recognize when to reach for this in a real cluster.', 'বাস্তব ক্লাস্টারে কখন এটি নিতে হবে তা বুঝতে পারবেন।'),
      l('Run the key kubectl commands and read the manifest fields.', 'মূল kubectl কমান্ড চালাতে ও ম্যানিফেস্ট ফিল্ড পড়তে পারবেন।'),
    ],
    advantages: l(`Understanding ${en.toLowerCase()} lets you run resilient, self-healing workloads at scale.`, `${bn} বোঝা আপনাকে স্কেলে স্থিতিস্থাপক, স্ব-নিরাময়ী ওয়ার্কলোড চালাতে দেয়।`),
    interview: l(`Show the manifest or kubectl command for ${en.toLowerCase()}, explain what it does, and name a trade-off or pitfall.`, `${bn}-এর ম্যানিফেস্ট বা kubectl কমান্ড দেখান, কী করে ব্যাখ্যা করুন, ও একটি ট্রেড-অফ বা ঝুঁকি বলুন।`),
    glossary: [
      { term: l('Pod', 'পড'), definition: l('The smallest deployable unit — one or more containers sharing network and storage.', 'ক্ষুদ্রতম ডিপ্লয়যোগ্য একক—নেটওয়ার্ক ও স্টোরেজ শেয়ার করা এক বা একাধিক কন্টেইনার।') },
      { term: l('Controller', 'কন্ট্রোলার'), definition: l('A loop that keeps actual cluster state matching the declared desired state.', 'একটি লুপ যা ক্লাস্টারের বর্তমান অবস্থাকে ঘোষিত কাঙ্ক্ষিত অবস্থার সঙ্গে মেলায়।') },
    ],
  }
  topic.exam = buildExam(topic, { distractors, subject: 'kubernetes' })
  return topic
})

